const ReaderModal = ({ book, onClose }: { book: Book; onClose: () => void }) => {
  const [activeChapterId, setActiveChapterId] = useState(book.chapters[0].id);
  const activeChapter = book.chapters.find(c => c.id === activeChapterId) || book.chapters[0];
  const contentRef = useRef<HTMLDivElement>(null);
  const { playHover, playClick } = useSound();

  // TTS State
  const [isPlaying, setIsPlaying] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null);

  // Timing state to handle pause/resume offsets
  const startTimeRef = useRef<number>(0);
  const elapsedTimeRef = useRef<number>(0);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'unset';
      stopAudio(true); // Stop and reset on unmount/close
    };
  }, []);

  // Stop audio when changing chapters
  useEffect(() => {
    stopAudio(true);
    if (contentRef.current) {
      contentRef.current.scrollTop = 0;
    }
  }, [activeChapterId]);

  const stopAudio = (resetBuffer = false) => {
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch (e) { /* ignore if already stopped */ }
      sourceNodeRef.current = null;
    }

    setIsPlaying(false);
    setIsPaused(false);
    setIsLoadingAudio(false);

    if (resetBuffer) {
        elapsedTimeRef.current = 0;
        audioBufferRef.current = null;
    } else {
        elapsedTimeRef.current = 0;
    }
  };

  const playBuffer = (buffer: AudioBuffer, offset: number = 0) => {
    if (!audioContextRef.current) return;

    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = 1.15; // Speed up voice slightly
    source.connect(audioContextRef.current.destination);

    source.onended = () => {
       // This fires when stopped manually AND when finished naturally.
       // We only want to auto-reset if it finished naturally.
       // However, setting state here is safe as long as manual handlers update state first.
       // Since manual stop updates state immediately, this effect is minor, 
       // but we'll use a check inside the component state to determine UI.
       setIsPlaying(false);
    };

    sourceNodeRef.current = source;
    source.start(0, offset);
    startTimeRef.current = audioContextRef.current.currentTime;
    setIsPlaying(true);
    setIsPaused(false);
  };

  const handleTogglePlay = async () => {
    // 1. If currently playing, PAUSE it.
    if (isPlaying) {
       if (audioContextRef.current && sourceNodeRef.current) {
          sourceNodeRef.current.stop();
          // Calculate how much we played *adjusted for playback rate*
          // (elapsed real time) * rate = (elapsed audio time)
          const rawElapsed = audioContextRef.current.currentTime - startTimeRef.current;
          elapsedTimeRef.current += rawElapsed * 1.15; 
       }
       setIsPlaying(false);
       setIsPaused(true);
       return;
    }

    // 2. If paused and we have buffer, RESUME it.
    if (isPaused && audioBufferRef.current) {
        playBuffer(audioBufferRef.current, elapsedTimeRef.current);
        return;
    }

    // 3. If starting from scratch (or reset).
    if (!process.env.API_KEY) {
      alert("Chave API não configurada.");
      return;
    }

    setIsLoadingAudio(true);
    playClick();

    try {
      const plainText = stripHtml(activeChapter.content);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: {
            parts: [{ text: plainText }]
        },
        config: {
          responseModalities: ['AUDIO'],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }
            }
          }
        }
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

      if (!base64Audio) {
        throw new Error("Nenhum áudio gerado");
      }

      // Initialize Audio Context if needed
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
      }

      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const audioBytes = decodeBase64(base64Audio);
      const audioBuffer = await decodePCM(audioBytes, audioContextRef.current, 24000, 1);

      audioBufferRef.current = audioBuffer;
      elapsedTimeRef.current = 0;

      playBuffer(audioBuffer);

    } catch (error) {
      console.error("Erro ao gerar áudio:", error);
      alert("Falha ao gerar voz. Verifique a chave API ou tente novamente.");
      setIsLoadingAudio(false);
    } finally {
      setIsLoadingAudio(false);
    }
  };

  const handleStop = () => {
    stopAudio(false); // Keeps buffer but resets time to 0
  };

  const renderInteractiveComponent = (type: InteractiveComponentType, data?: any) => {
    switch (type) {
      case 'ConsoleSimulator': return <ConsoleSimulator />;
      case 'FlameBalance': return <FlameBalance />;
      case 'ServerLayers': return <ServerLayers />;
      case 'DialogueTree': return <DialogueTree data={data} />;
      case 'RegexLab': return <RegexLab />;
      case 'CrisisDecision': return <CrisisDecision />;
      default: return null;
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex bg-void-900 animate-in fade-in duration-300">
      {/* Sidebar Navigation */}
      <div className="w-80 border-r border-white/5 flex flex-col bg-zinc-950 hidden md:flex shrink-0">
        <div className="p-8 border-b border-white/5">
