          {filteredBooks.map(book => (
            <BookCard 
              key={book.id} 
              book={book} 
              onClick={() => onOpenBook(book)} 
              onMouseMove={(e) => handleMouseMove(e, book)}
              onMouseLeave={handleMouseLeave}
            />
          ))}
        </div>
      </div>
      {tooltip && <LibraryTooltip book={tooltip.book} x={tooltip.x} y={tooltip.y} />}
    </section>
  );
};

const ReaderModal = ({ book, onClose }: { book: Book; onClose: () => void }) => {
  const [activeChapterId, setActiveChapterId] = useState(book.chapters[0].id);
  const activeChapter = book.chapters.find(c => c.id === activeChapterId) || book.chapters[0];
  const contentRef = useRef<HTMLDivElement>(null);
  const { playHover, playClick } = useSound();

  // TTS State
  const [isPlaying, setIsPlaying] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);
  const [selectedVoice, setSelectedVoice] = useState('Kore');
  const [isReadingMode, setIsReadingMode] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1.0);

  // Adaptation State
  const [targetAge, setTargetAge] = useState('original');
  const [rewrittenContent, setRewrittenContent] = useState<string | null>(null);
  const [isRewriting, setIsRewriting] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null);

  // Timing state to handle pause/resume offsets
  const startTimeRef = useRef<number>(0);
  const elapsedTimeRef = useRef<number>(0);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'unset';
      stopAudio(true); // Stop and reset on unmount/close
    };
  }, []);

  // Stop audio when changing chapters and Handle Adaptation
  useEffect(() => {
    stopAudio(true);
    if (contentRef.current) {
      contentRef.current.scrollTop = 0;
    }

    // Handle Adaptation Logic on Chapter Change
    if (targetAge !== 'original') {
        fetchRewrittenContent(targetAge, activeChapter.content);
    } else {
        setRewrittenContent(null);
    }
  }, [activeChapterId]);

  const fetchRewrittenContent = async (age: string, originalContent: string) => {
    if (!process.env.API_KEY) {
        // Fail silently or show default
        setRewrittenContent(null);
        return;
    }

    setIsRewriting(true);
    setRewrittenContent(null); // Clear previous rewritten content while loading

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Reescreva o conteúdo HTML abaixo para um leitor de faixa etária: ${age}. 
        IMPORTANTE: 
        1. Mantenha a estrutura exata das tags HTML (h1, h2, p, ul, li, strong). Não remova tags.
        2. Adapte o vocabulário, o tom e os exemplos para serem compreensíveis e engajantes para essa idade.
        3. Mantenha o idioma Português do Brasil.
        4. O objetivo é educação sobre moderação de comunidades, mantenha a lição moral intacta.

        Conteúdo HTML:
        ${originalContent}`;

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: [{ parts: [{ text: prompt }] }]
        });

        const newText = response.text;
        if (newText) {
            setRewrittenContent(newText);
        }
    } catch (error) {
        console.error("Erro ao reescrever conteúdo:", error);
        // Fallback to original in case of error
        setRewrittenContent(null);
    } finally {
        setIsRewriting(false);
    }
  };

  const stopAudio = (resetBuffer = false) => {
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch (e) { /* ignore if already stopped */ }
      sourceNodeRef.current = null;
    }

    setIsPlaying(false);
    setIsPaused(false);
    setIsLoadingAudio(false);

    if (resetBuffer) {
        elapsedTimeRef.current = 0;
        audioBufferRef.current = null;
    } else {
        elapsedTimeRef.current = 0;
    }
  };

  const playBuffer = (buffer: AudioBuffer, offset: number = 0) => {
    if (!audioContextRef.current) return;

    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackSpeed; // Apply current speed
    source.connect(audioContextRef.current.destination);

    source.onended = () => {
       // This fires when stopped manually AND when finished naturally.
       // We only want to auto-reset if it finished naturally.
       // However, setting state here is safe as long as manual handlers update state first.
       // Since manual stop updates state immediately, this effect is minor, 
       // but we'll use a check inside the component state to determine UI.
       setIsPlaying(false);
    };

    sourceNodeRef.current = source;
    source.start(0, offset);
    startTimeRef.current = audioContextRef.current.currentTime;
    setIsPlaying(true);
    setIsPaused(false);
  };

  const handleSpeedChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newSpeed = parseFloat(e.target.value);

    // If playing, we need to adjust the source node immediately without resetting audio
    if (isPlaying && sourceNodeRef.current && audioContextRef.current) {
        // 1. Calculate how much buffer has been played so far with the OLD speed
        const now = audioContextRef.current.currentTime;
        const rawTimeSinceStart = now - startTimeRef.current;
        const bufferConsumed = rawTimeSinceStart * playbackSpeed;

        // 2. Add this to the accumulated elapsed time
        elapsedTimeRef.current += bufferConsumed;

        // 3. Reset the start time to NOW, so future calculations start from here
        startTimeRef.current = now;

        // 4. Update the speed on the live node
        sourceNodeRef.current.playbackRate.value = newSpeed;
    }

    setPlaybackSpeed(newSpeed);
  };

  const handleTogglePlay = async () => {
    // 1. If currently playing, PAUSE it.
    if (isPlaying) {
       if (audioContextRef.current && sourceNodeRef.current) {
          sourceNodeRef.current.stop();
          // Calculate elapsed time considering the speed it was playing at
          const rawElapsed = audioContextRef.current.currentTime - startTimeRef.current;
          elapsedTimeRef.current += rawElapsed * playbackSpeed; 
       }
       setIsPlaying(false);
       setIsPaused(true);
       return;
    }

    // 2. If paused and we have buffer, RESUME it.
    if (isPaused && audioBufferRef.current) {
        // Resume from the calculated buffer offset
        // Note: The offset passed to start() is in seconds of buffer data, independent of playback rate
        playBuffer(audioBufferRef.current, elapsedTimeRef.current);
        return;
    }

    // 3. If starting from scratch (or reset).
    if (!process.env.API_KEY) {
      alert("Chave API não configurada.");
      return;
    }

    setIsLoadingAudio(true);
    playClick();

    try {
      // Use rewritten content if available, otherwise original
      const contentToRead = rewrittenContent || activeChapter.content;
      const plainText = stripHtml(contentToRead);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: {
            parts: [{ text: plainText }]
        },
        config: {
          responseModalities: ['AUDIO'],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: selectedVoice }
            }
          }
        }
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

      if (!base64Audio) {
        throw new Error("Nenhum áudio gerado");
      }

      // Initialize Audio Context if needed
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
      }

      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const audioBytes = decodeBase64(base64Audio);
      const audioBuffer = await decodePCM(audioBytes, audioContextRef.current, 24000, 1);

      audioBufferRef.current = audioBuffer;
      elapsedTimeRef.current = 0;

      playBuffer(audioBuffer);

    } catch (error) {
      console.error("Erro ao gerar áudio:", error);
      alert("Falha ao gerar voz. Verifique a chave API ou tente novamente.");
      setIsLoadingAudio(false);
    } finally {
      setIsLoadingAudio(false);
    }
  };

  const handleStop = () => {
    stopAudio(false); // Keeps buffer but resets time to 0
  };

  const handleAgeChange = (newAge: string) => {
      playClick();
      setTargetAge(newAge);
      stopAudio(true); // Reset audio as content will change

      if (newAge === 'original') {
          setRewrittenContent(null);
      } else {
          fetchRewrittenContent(newAge, activeChapter.content);
      }
  };

  const renderInteractiveComponent = (type: InteractiveComponentType, data?: any) => {
    switch (type) {
      case 'ConsoleSimulator': return <ConsoleSimulator />;
      case 'FlameBalance': return <FlameBalance />;
      case 'ServerLayers': return <ServerLayers />;
      case 'DialogueTree': return <DialogueTree data={data} />;
      case 'RegexLab': return <RegexLab />;
      case 'CrisisDecision': return <CrisisDecision />;
      default: return null;
    }
  };

  const displayedContent = rewrittenContent || activeChapter.content;

  return (
    <div className="fixed inset-0 z-50 flex bg-void-900 animate-in fade-in duration-300">
      {/* Sidebar Navigation - HIDE in Reading Mode */}
      {!isReadingMode && (
        <div className="w-80 border-r border-white/5 flex flex-col bg-zinc-950 hidden md:flex shrink-0">
          <div className="p-8 border-b border-white/5">
            <h3 className="font-display text-xl text-white font-bold leading-tight">{book.title}</h3>
            <p className="font-serif text-sm text-zinc-500 italic mt-2">{book.subtitle}</p>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-1 scrollbar-thin scrollbar-thumb-zinc-800">
            {book.chapters.map((chapter, idx) => (
              <button
                key={chapter.id}
                onMouseEnter={playHover}
                onClick={() => { playClick(); setActiveChapterId(chapter.id); }}
                className={`w-full text-left p-3 text-sm font-sans transition-all rounded-lg ${
                  activeChapterId === chapter.id 
                    ? 'bg-zinc-900 text-flame-500 border-l-2 border-flame-500' 
                    : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-900/50'
                }`}
              >
                <span className="opacity-50 mr-2">{idx + 1}.</span> {chapter.title.replace(/^\d+\.\s/, '')}
              </button>
            ))}
          </div>
          <div className="p-6 border-t border-white/5">
            <button 
              onMouseEnter={playHover}
              onClick={() => { playClick(); onClose(); }}
              className="flex items-center text-zinc-500 hover:text-white transition-colors text-sm uppercase tracking-widest font-bold"
            >
              <X className="w-4 h-4 mr-2" /> Fechar Livro
            </button>
          </div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden bg-void-900 relative">
        {/* Mobile Close Button - Hide in Reading Mode for immersion, but keep logic if needed or let Exit Button handle it */}
        {!isReadingMode && (
           <div className="md:hidden absolute top-4 right-4 z-50">
             <button 
              onClick={() => { playClick(); onClose(); }} 
              className="p-2 bg-zinc-800 rounded-full text-white"
             >
               <X className="w-5 h-5"/>
             </button>
           </div>
        )}

        {/* Floating Exit Reading Mode Button */}
        {isReadingMode && (
          <button
            onClick={() => { playClick(); setIsReadingMode(false); }}
            className="fixed top-6 right-6 z-50 p-3 bg-void-900/90 text-zinc-500 hover:text-flame-500 border border-zinc-800 rounded-full transition-all shadow-xl backdrop-blur-sm animate-in fade-in zoom-in duration-300"
            title="Sair do Modo Leitura"
          >
            <X className="w-5 h-5" />
          </button>
        )}

        <div ref={contentRef} className="flex-1 overflow-y-auto p-6 md:p-16 lg:p-24 w-full">
           <div className={`max-w-4xl mx-auto transition-all duration-500 ${isReadingMode ? 'max-w-3xl' : ''}`}>

             {/* Header Controls - Hide in Reading Mode */}
             {!isReadingMode && (
               <div className="flex flex-col gap-4 mb-4">

                 <div className="flex items-center justify-between">
                   <span className="text-flame-500 text-xs font-bold tracking-[0.2em] uppercase block">Capítulo {book.chapters.findIndex(c => c.id === activeChapterId) + 1}</span>

                   <div className="flex items-center gap-2">

                      {/* Age Selection */}
                      <div className="relative group mr-2 hidden lg:block">
                        <div className="absolute inset-y-0 left-0 flex items-center pl-2 pointer-events-none text-zinc-500">
                          {isRewriting ? <Loader2 className="w-3 h-3 animate-spin"/> : <User className="w-3 h-3" />}
                        </div>
                        <select
                          value={targetAge}
                          onChange={(e) => handleAgeChange(e.target.value)}
                          disabled={isRewriting}
                          className="appearance-none bg-zinc-900 border border-zinc-700 text-zinc-300 text-[10px] uppercase tracking-wider py-1.5 pl-7 pr-6 rounded-full cursor-pointer hover:border-flame-500 focus:outline-none focus:border-flame-500 transition-colors disabled:opacity-50"
                        >
                          {AGE_OPTIONS.map(opt => (
                            <option key={opt.value} value={opt.value}>{opt.label}</option>
                          ))}
                        </select>
                        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-zinc-500">
                          <ChevronRight className="h-3 w-3 rotate-90" />
                        </div>
                      </div>

                      {/* Voice Selection */}
                      <div className="relative group mr-2">
                        <div className="absolute inset-y-0 left-0 flex items-center pl-2 pointer-events-none text-zinc-500">
                          <Mic className="w-3 h-3" />
                        </div>
                        <select
                          value={selectedVoice}
                          onChange={(e) => {
                            playClick();
                            setSelectedVoice(e.target.value);
                            stopAudio(true); // Reset audio so next click generates with new voice
                          }}
                          className="appearance-none bg-zinc-900 border border-zinc-700 text-zinc-300 text-[10px] uppercase tracking-wider py-1.5 pl-7 pr-6 rounded-full cursor-pointer hover:border-flame-500 focus:outline-none focus:border-flame-500 transition-colors"
                        >
                          {VOICES.map(v => (
                            <option key={v} value={v}>{v}</option>
                          ))}
                        </select>
                        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-zinc-500">
                          <ChevronRight className="h-3 w-3 rotate-90" />
                        </div>
                      </div>

                      {/* TTS Controls */}
                      <div className="flex items-center gap-1 bg-zinc-900 border border-zinc-700 rounded-full p-1 pr-3">
                          <button
                          onClick={handleTogglePlay}
                          disabled={isLoadingAudio}
                          className={`flex items-center justify-center w-8 h-8 rounded-full transition-all ${
                              isPlaying 
                              ? 'text-flame-500 hover:bg-zinc-800' 
                              : isPaused 
                                  ? 'text-green-500 hover:bg-zinc-800'
                                  : 'text-zinc-400 hover:text-white hover:bg-zinc-800'
                          }`}
                          title={isPlaying ? "Pausar" : isPaused ? "Retomar" : "Ouvir Capítulo"}
                          >
                          {isLoadingAudio ? (
                              <Loader2 className="w-4 h-4 animate-spin" />
                          ) : isPlaying ? (
                              <Pause className="w-4 h-4 fill-current" />
                          ) : (
                              <Play className="w-4 h-4 fill-current" />
                          )}
                          </button>

                          {(isPlaying || isPaused) && (
                              <button
                                  onClick={handleStop}
                                  className="flex items-center justify-center w-8 h-8 rounded-full text-zinc-500 hover:text-red-500 hover:bg-zinc-800 transition-all"
                                  title="Parar"
                              >
                                  <StopCircle className="w-4 h-4" />
                              </button>
                          )}

                          <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest ml-1 hidden sm:inline-block">
                              {isLoadingAudio ? "Carregando..." : isPlaying ? "Ouvindo" : isPaused ? "Pausado" : "Ouvir"}
                          </span>
                      </div>

                      {/* Speed Control (Simple) */}
                      <div className="relative group ml-1 flex items-center gap-1 bg-zinc-900 border border-zinc-700 rounded-full px-2 py-1" title="Velocidade da Voz">
                          <Gauge className="w-3 h-3 text-zinc-500" />
                          <input 
                              type="range" 
                              min="0.5" 
                              max="2.0" 
                              step="0.1" 
                              value={playbackSpeed}
                              onChange={handleSpeedChange}
                              className="w-16 h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-flame-500"
                          />
                          <span className="text-[9px] w-6 text-right font-mono text-zinc-400">{playbackSpeed.toFixed(1)}x</span>
                      </div>

                      {/* Reading Mode Toggle */}
                      <button
                        onClick={() => { playClick(); setIsReadingMode(true); }}
                        className="flex items-center justify-center w-8 h-8 rounded-full bg-zinc-900 border border-zinc-700 text-zinc-400 hover:text-flame-500 hover:border-flame-500 transition-all ml-2"
                        title="Modo Leitura (Foco)"
                      >
                         <BookOpen className="w-4 h-4" />
                      </button>

                       {/* Quick Jump Dropdown for easy navigation (essential for mobile) */}
                       <div className="relative group ml-2">
                          <select
                              value={activeChapterId}
                              onChange={(e) => {
                                  playClick();
                                  setActiveChapterId(e.target.value);
                              }}
                              className="appearance-none bg-zinc-900/80 border border-zinc-700 text-zinc-300 text-xs uppercase tracking-wider py-2 pl-3 pr-8 rounded cursor-pointer hover:border-flame-500 focus:outline-none focus:border-flame-500 transition-colors"
                          >
                              {book.chapters.map((chapter, idx) => (
                                  <option key={chapter.id} value={chapter.id}>
                                      {idx + 1}. {chapter.title.replace(/^\d+\.\s/, '').substring(0, 30)}{chapter.title.length > 30 ? '...' : ''}
                                  </option>
                              ))}
                          </select>
                          <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-zinc-500">
                              <ChevronRight className="h-3 w-3 rotate-90" />
                          </div>
                       </div>
                   </div>
                 </div>
               </div>
             )}

             <h1 className={`font-display text-3xl md:text-5xl text-white mb-12 leading-tight transition-all ${isReadingMode ? 'text-center mt-12' : ''}`}>{activeChapter.title.replace(/^\d+\.\s/, '')}</h1>

             {isRewriting ? (
                 <div className="flex flex-col items-center justify-center h-64 text-zinc-500 animate-pulse">
                     <Sparkles className="w-8 h-8 mb-4 text-flame-500" />
                     <p className="font-display text-lg">Adaptando sabedoria para {targetAge}...</p>
                 </div>
             ) : (
                <div 
                className={`prose prose-invert prose-lg md:prose-xl font-serif text-zinc-300 leading-loose prose-headings:font-display prose-headings:text-white prose-blockquote:border-flame-500 prose-blockquote:text-zinc-400 prose-a:text-flame-500 prose-strong:text-white prose-code:text-flame-500 prose-code:bg-zinc-900 prose-code:px-1 prose-code:rounded prose-code:font-normal prose-pre:bg-zinc-950 prose-pre:border prose-pre:border-zinc-800 transition-opacity duration-500 ${isReadingMode ? 'opacity-90' : ''}`}
                dangerouslySetInnerHTML={{ __html: displayedContent }}
                />
             )}

             {/* Render Interactive Component if present and not rewriting */}
             {!isRewriting && activeChapter.interactiveComponent && (
               <div className="mt-8 animate-in slide-in-from-bottom-4 duration-700">
                 {renderInteractiveComponent(activeChapter.interactiveComponent, activeChapter.interactiveData)}
               </div>
             )}

             {/* Footer Navigation - Hide in Reading Mode */}
             {!isReadingMode && (
               <div className="mt-24 pt-12 border-t border-white/5 flex justify-between">
                  <button 
                    disabled={book.chapters.findIndex(c => c.id === activeChapterId) === 0}
                    onMouseEnter={playHover}
                    onClick={() => {
                       playClick();
                       const idx = book.chapters.findIndex(c => c.id === activeChapterId);
                       if (idx > 0) setActiveChapterId(book.chapters[idx-1].id);
                    }}
                    className="text-zinc-500 hover:text-white disabled:opacity-20 transition-colors uppercase tracking-widest text-sm font-bold"
                  >
                    Anterior
                  </button>
                  <button 
                    disabled={book.chapters.findIndex(c => c.id === activeChapterId) === book.chapters.length - 1}
                    onMouseEnter={playHover}
                    onClick={() => {
                       playClick();
                       const idx = book.chapters.findIndex(c => c.id === activeChapterId);
                       if (idx < book.chapters.length - 1) setActiveChapterId(book.chapters[idx+1].id);
                    }}
                    className="text-flame-500 hover:text-white disabled:opacity-20 transition-colors uppercase tracking-widest text-sm font-bold"
                  >
                    Próximo
                  </button>
               </div>
             )}
           </div>
        </div>
      </div>
    </div>
  );
}

