import { Flame, BookOpen, Scroll, X, ChevronRight, ChevronLeft, Menu, Shield, Terminal, Activity, Layers, MessageSquare, Code, AlertTriangle, Volume2, StopCircle, Loader2, Pause, Play, Mic, Maximize2, Minimize2, Gauge, Sparkles, User, Crown, Cpu, Bell, Gavel, Scale, Eye, ArrowRight, MessageCircle, Search } from 'lucide-react';
