              ))}
            </div>
          </div>
        </div>

        {filteredBooks.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredBooks.map(book => (
                <BookCard 
                key={book.id} 
