// --- Debate Logic ---

interface Comment {
  id: string;
  author: string;
  text: string;
  likes: number;
  time: string;
}

interface TopicData {
  id: string;
  icon: any;
  title: string;
  question: string;
  comments: Comment[];
}

const DebateModal = ({ 
  topic, 
  onClose,
  onAddComment,
  onLikeComment
}: { 
  topic: TopicData; 
  onClose: () => void;
  onAddComment: (text: string, author: string) => void;
  onLikeComment: (commentId: string) => void;
}) => {
  const [step, setStep] = useState<'login' | 'discussion'>('login');
  const [username, setUsername] = useState('');
  const [newComment, setNewComment] = useState('');
  const { playClick, playHover } = useSound();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.trim()) {
      playClick();
      setStep('discussion');
    }
  };

  const handleSubmitComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (newComment.trim()) {
      playClick();
      onAddComment(newComment, username);
      setNewComment('');
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm animate-in fade-in p-4">
      <div className="w-full max-w-2xl bg-zinc-950 border border-zinc-800 rounded-xl overflow-hidden shadow-2xl relative">
