interface Comment {
  id: string;
  author: string;
  text: string;
  likes: number;
  time: string;
}

interface TopicData {
  id: string;
  icon: any;
  title: string;
  question: string;
  comments: Comment[];
}

const DebateModal = ({ 
  topic, 
  onClose,
  onAddComment,
  onLikeComment
}: { 
